external_knowledge:
- "shining star" is a metaphor for an artist with high popularity;
- "casts the longest shadow" metaphorically refers to having the highest influence or popularity;
- "aggregated glow" means the sum of the popularity ratings of each artist's tracks;
- The top artist is determined by the highest total popularity.

sql:
SELECT AVG(popularity) AS AveragePopularity
FROM analytics
WHERE listen_count > 50;

SELECT AVG(t.danceability) AS "Average Danceability"
FROM tracks t
JOIN track_features tf ON t.track_id = tf.track_id AND tf.feature_name = 'danceability';

external_knowledge:
- Brightest stars: metaphoric expression for the most popular tracks; 
- Radiant: metaphorically used to indicate high track popularity;
- Top 10: limits the results to the 10 most popular tracks.

sql:
SELECT name
FROM artists
WHERE created_at = (
  SELECT MAX(created_at)
  FROM artists
);
